import React from 'react';
import styles from './Main.module.css';

function Main() {
  return (
    <main className={styles.main}>
      <h2>세상에 따뜻함과
      긍정의 에너지를 더하다!</h2>
      <p>Positalk은 당신의 메시지를 더욱 긍정적이고 따뜻하게 만들어주는 AI 서비스입니다.</p>
      <p>일상 대화부터 비즈니스 커뮤니케이션까지, 모든 상황에서 최적의 표현을 제안합니다.</p>
    </main>
  );
}

export default Main;
